class Solution {
public:
    string reformatNumber(string number) {
        string digits;
        for (char c : number) {
            if (isdigit(c)) {
                digits += c;
            }
        }
        string result;
        while (digits.size() > 4) {
            result += digits.substr(0, 3) + "-";
            digits = digits.substr(3);
        }
        if (digits.size() == 4) {
            result += digits.substr(0, 2) + "-" + digits.substr(2);
        } else {
            result += digits;
        }
        return result;
    }
};
